482	template <class... Ops>
483	struct Sm90VisitorImplBase {
484	  // Shared memory allocation
485	  using SharedStorage = tuple<typename Ops::SharedStorage...>;
486	  // Host side fusion arguments
487	  using Arguments = tuple<typename Ops::Arguments...>;
488	  // Device side fusion params (Kernel-entry API)
489	  using Params = tuple<typename Ops::Params...>;
490	  // Tensormap argument type used in ptr-array epilogues. The pack expansion is
491	  // delegated to tensormaps_tuple_for above; spelling it inline here trips an
492	  // MSVC bug with alias-template pack expansion over an enclosing class's pack.
493	  template <bool IsLoad>
494	  using TensorMaps = typename tensormaps_tuple_for<IsLoad, Ops...>::type;
495	
496	  template <class ProblemShape>
497	  static constexpr Params
498	  to_underlying_arguments(ProblemShape const& problem_shape, Arguments const& args, void* workspace) {
499	    uint8_t* op_workspace = reinterpret_cast<uint8_t*>(workspace);
500	    return transform_apply(tuple<Ops...>{}, args,
501	      [&] (auto&& op, auto const& op_args) CUTLASS_LAMBDA_FUNC_INLINE {
502	        using Op = cute::remove_cvref_t<decltype(op)>;
503	        auto ret = Op::to_underlying_arguments(problem_shape, op_args, op_workspace);
504	        if (op_workspace != nullptr) {
505	          size_t op_workspace_size = Op::get_workspace_size(problem_shape, op_args);
506	          op_workspace += round_nearest(op_workspace_size, MinWorkspaceAlignment);
507	        }
508	        return ret;
509	      },
510	      [] (auto&&... op_params) CUTLASS_LAMBDA_FUNC_INLINE { return cute::make_tuple(op_params...); }
511	    );
512	  }
513	
514	  template <class ProblemShape>
515	  static bool
516	  can_implement(ProblemShape const& problem_shape, Arguments const& args) {
517	    return transform_apply(tuple<Ops...>{}, args,
518	      [&] (auto&& op, auto const& op_args) CUTLASS_LAMBDA_FUNC_INLINE {
519	        using Op = cute::remove_cvref_t<decltype(op)>;
520	        return Op::can_implement(problem_shape, op_args);
521	      },
